import{_ as r,o as t,c as p,j as e,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"掠夺者动力装甲","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/3.防具/1.无支线/掠夺者动力装甲.md","filePath":"4.资源分区/7.物品与装备/3.防具/1.无支线/掠夺者动力装甲.md"}'),o={name:"4.资源分区/7.物品与装备/3.防具/1.无支线/掠夺者动力装甲.md"};function d(_,a,l,i,c,h){return t(),p("div",null,[...a[0]||(a[0]=[e("h1",{id:"掠夺者动力装甲",tabindex:"-1"},[n("掠夺者动力装甲 "),e("a",{class:"header-anchor",href:"#掠夺者动力装甲","aria-label":'Permalink to "掠夺者动力装甲"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),s('<h1 id="掠夺者动力装甲-1" tabindex="-1">掠夺者动力装甲 <a class="header-anchor" href="#掠夺者动力装甲-1" aria-label="Permalink to &quot;掠夺者动力装甲&quot;">​</a></h1><p>掠夺者动力装甲<br> 1000<br> 科技本质<br> 这……怎么说呢，与其说它是一套动力装甲，我觉得叫移动垃圾堆会更合适。</p><p>废土上的动力装甲大多都因为长期缺乏保养而缺胳膊少腿的，这样的动力装甲必定会在战斗中留下短板，而且在这个技术落后，材料稀缺的世界重新制造动力装甲堪比一步登天，毕竟不是人人都有英克雷那样的技术。</p><p>于是，掠夺者们直接把一堆废铜烂铁经过简单的焊接将它装到动力骨架上，这样一来也可以提供防御力，二来哪怕是这些破烂损坏掉也不心疼。当然， 锈迹斑斑的外观让人怀疑它是否有防护性能。但对于废土人来说，这一套废材拼接而成的动力装甲已经足以使自己获得强于他人的生存本钱，因此掠夺者之力动力装甲十分地受欢迎（如果你无法获得其他动力装甲的话）。</p><p>护甲值5/5 盔甲减值2</p><p>类型：重甲</p><p>能源：相比于这些大势力，废土上的掠夺者们无论是科技，还是兵力，还是财力，还是科研力量，都完全无法与那些大势力相提比论——他们甚至连一枚能用的聚变核心都很难找到。因此她们选择在动力装甲背后改装了一个巨大的蒸汽锅炉，来驱动整个动力装甲。但是需要注意的是，将原先的聚变能源改装成蒸汽锅炉确实较为适合战后的废土，但是锅炉带来的足以将人烤焦的热量是无法被忽视的 ，为了防止被烤焦，机甲本身很多的封闭设计都被打开用于散热，这进一步降低了掠夺者动力装甲本就所剩无几的防护能力，在蒸汽锅炉满载后可以支持该装甲运行15分钟。<br> 驱动装甲运行的燃料可以是任何可燃物，当然还需要水。<br> 一块1分的电池可以驱动掠夺者动力装甲运作24小时。</p><p>速度：掠夺者动力装甲会额外再提供15米移动速度。</p><p>简易机甲：毫无疑问，废土上的掠夺者们无法维修相对脆弱的电子目镜，这台运行起来叮叮当当，喷涌黑烟的机甲，也无法为穿戴者提供（除心理安慰之外）像样的防护，人物的头颅，关节、脖颈处直接裸露在外，可被敌人直接攻击，但焊接，甚至系挂的铁片，还是勉强为穿戴者提供了额外的1点护甲加值。（已计入护甲值中）</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
